    70→function extractEffortLevel(text: string): EffortLevel | null {
    71→  const match = text.match(/level\s+(QUICK|STANDARD|THOROUGH|TRIVIAL)/i);
    72→  return match ? (match[1].toUpperCase() as EffortLevel) : null;
    73→}
    74→
    75→function extractISCSatisfaction(text: string): ISCDocument['satisfaction'] | null {
    76→  // Match patterns like "6 ISC criteria, all satisfied"
    77→  const allSatisfied = text.match(/(\d+)\s*(?:ISC\s*)?criteria?,?\s*all\s*satisfied/i);
